7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	const COMPONENT_BASE_PREMIUM = 25;
10	const BLOCK_SIZE = 3;
11	const BLOCK_BASE_PREMIUM = 60;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;
21	
22	const itemsBaseTotal = (items: Item[]): number => {
23	  const mainItemsBase = items
24	    .filter((i) => !isComponent(i))
25	    .reduce((sum, i) => sum + BASE_PREMIUMS[i.type], 0);
26	
27	  const componentCounts = new Map<string, number>();
28	  items.filter(isComponent).forEach((i) => {
29	    componentCounts.set(i.type, (componentCounts.get(i.type) ?? 0) + 1);
30	  });
31	
32	  let componentsBase = 0;
33	  componentCounts.forEach((count) => {
34	    if (count === BLOCK_SIZE) {
35	      componentsBase += BLOCK_BASE_PREMIUM;
36	    } else {
37	      componentsBase += count * COMPONENT_BASE_PREMIUM;
38	    }
39	  });
40	
41	  return mainItemsBase + componentsBase;
42	};
43	
44	const quoteStep = (step: Step): QuoteResult => {
45	  const itemsBase = itemsBaseTotal(step.items);
46	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
47	  const premium = Math.ceil(itemsBase + firstInsurance) + PROCESSING_FEE;
48	  return { premium };
49	};
50	
51	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
52	  const results = scenario.steps.map(quoteStep);
53	  return { results };
54	};
